static void pcibase_realize(PCIDevice *pdev, Error **errp)
{
    PCIBaseState *s = PCIBASE_DEVICE(pdev);

    /* Setup two MMIO BARs as required by the driver */
    s->num_bars = 2;

    /* BAR 0: XGMAC (MAC, MTL, DMA) - 64KB */
    s->bar_info[0].index = 0;
    s->bar_info[0].type = BAR_TYPE_MMIO;
    s->bar_info[0].size = 0x10000; /* 64 KiB */
    s->bar_info[0].name = "amd-xgbe-xgmac";
    s->bar_info[0].sparse = false;

    /* BAR 1: XPCS (PCS, SerDes, I2C, PROP) - 64KB */
    s->bar_info[1].index = 1;
    s->bar_info[1].type = BAR_TYPE_MMIO;
    s->bar_info[1].size = 0x10000; /* 64 KiB */
    s->bar_info[1].name = "amd-xgbe-xpcs";
    s->bar_info[1].sparse = false;

    /* Allocate backing for XGMAC BAR */
    s->xmac_backing_size = s->bar_info[0].size;
    s->xmac_backing = g_malloc0(s->xmac_backing_size);

    /* Allocate backing for XPCS BAR */
    s->xpcs_backing_size = s->bar_info[1].size;
    s->xpcs_backing = g_malloc0(s->xpcs_backing_size);

    for (int i = 0; i < s->num_bars = 2; i++) {
        pcibase_register_bar(pdev, s, &s->bar_info[i], errp);
        if (errp && *errp) {
            return;
        }
    }

    pcibase_dma_device_realize(pdev, errp);
    if (errp && *errp) {
        return;
    }
}
